import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

const gold = '#D4AF37';
const fancyFont = "'Playfair Display', serif";

// --- COMPACT WIG STORE ---
const WigStore = () => {
  const categories = [
    {
      type: "Human Hair",
      note: "100% authentic. Dyeable & lasts years.",
      items: [{ name: "Raw Cambodian", price: "85k", desc: "14\" frontal unit." }]
    },
    {
      type: "Premium Fibre",
      note: "Heat resistant. Pre-styled luxury.",
      items: [{ name: "Sleek Straight", price: "35k", desc: "Heat safe to 180°C." }]
    },
    {
      type: "Hair Blend",
      note: "Durable mix. Holds curls longer.",
      items: [{ name: "Piano Wavy", price: "25k", desc: "24\" high volume." }]
    }
  ];

  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '10px' }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ border: '1px solid #1a1a1a', backgroundColor: '#050505', borderRadius: '4px' }}>
          <div style={{ padding: '10px', borderBottom: '1px solid #111', textAlign: 'center' }}>
            <h3 style={{ color: gold, fontFamily: fancyFont, fontSize: '0.85rem', margin: '0 0 3px 0' }}>{cat.type}</h3>
            <p style={{ color: '#555', fontSize: '0.55rem', fontStyle: 'italic', margin: 0 }}>{cat.note}</p>
          </div>
          <div style={{ padding: '8px', textAlign: 'center' }}>
            {cat.items.map((item) => (
              <div key={item.name}>
                <div style={{ width: '100%', height: '140px', backgroundColor: '#0a0a0a', marginBottom: '8px', borderRadius: '2px' }}>
                   <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#1a1a1a', fontSize: '0.4rem' }}>IMAGE</div>
                </div>
                <h4 style={{ color: '#fff', fontSize: '0.7rem', margin: '0' }}>{item.name}</h4>
                <div style={{ color: gold, fontSize: '0.7rem', fontWeight: '600', margin: '3px 0' }}>₦{item.price}</div>
                <button style={{ background: 'none', border: `1px solid ${gold}44`, color: gold, padding: '3px 6px', cursor: 'pointer', fontSize: '0.5rem', letterSpacing: '1px' }}>ORDER</button>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [isVisible, setIsVisible] = useState(false);

  // Trigger animation on load
  useEffect(() => {
    setIsVisible(true);
  }, []);

  // Animation Styles
  const fadeInStyle = {
    opacity: isVisible ? 1 : 0,
    transform: isVisible ? 'translateY(0)' : 'translateY(20px)',
    transition: 'all 1s ease-out'
  };

  const navItemStyle = (item) => ({
    background: 'none', border: 'none', color: gold, fontSize: '0.65rem', cursor: 'pointer',
    letterSpacing: '2px', textTransform: 'uppercase', opacity: activeCategory === item ? 1 : 0.3,
    borderBottom: activeCategory === item ? `1px solid ${gold}` : 'none', paddingBottom: '4px',
    transition: '0.4s'
  });

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'Inter, sans-serif' }}>
      
      {/* HERO HEADER SECTION */}
      <header style={{ 
        padding: '60px 0 40px', 
        textAlign: 'center', 
        borderBottom: '1px solid #111',
        ...fadeInStyle 
      }}>
        <img src={Logo} alt="Logo" style={{ height: '120px', marginBottom: '40px' }} />
        
        {/* ANIMATED NAV GATES */}
        <div style={{ 
          display: 'flex', 
          gap: '25px', 
          justifyContent: 'center',
          transitionDelay: '0.5s',
          opacity: isVisible ? 1 : 0
        }}>
          {['Small Chops', 'Office Lunch', 'Wigs', 'About'].map((item) => (
            <button 
              key={item} 
              onClick={() => setActiveCategory(item)}
              style={navItemStyle(item)}
            >
              {item}
            </button>
          ))}
        </div>
      </header>

      {/* COMPACT MAIN CONTAINER */}
      <main style={{ maxWidth: '850px', margin: '0 auto', padding: '40px 15px', ...fadeInStyle, transitionDelay: '0.8s' }}>
        
        {/* Section Title */}
        <div style={{ textAlign: 'center', marginBottom: '35px' }}>
          <h2 style={{ color: gold, fontSize: '1.4rem', fontFamily: fancyFont, fontStyle: 'italic', letterSpacing: '2px' }}>
             {activeCategory === 'Small Chops' ? 'The Curation' : 
              activeCategory === 'Office Lunch' ? 'Corporate Dining' : 
              activeCategory === 'Wigs' ? 'The Hair Edit' : 'Our Story'}
          </h2>
          <div style={{ width: '40px', height: '1px', backgroundColor: gold, margin: '12px auto', opacity: 0.4 }}></div>
        </div>

        {/* Scaled-Down Content Wrapper */}
        <div style={{ transform: 'scale(0.92)', transformOrigin: 'top' }}> 
          {activeCategory === 'Small Chops' && <Menu />}
          {activeCategory === 'Office Lunch' && <Lunch />}
          {activeCategory === 'Wigs' && <WigStore />}
          {activeCategory === 'About' && (
            <div style={{ textAlign: 'center', padding: '20px', color: '#777', fontSize: '0.85rem', lineHeight: '2' }}>
              <p style={{ letterSpacing: '1px' }}>Àmí by T: Redefining luxury through taste and style.</p>
              <p>Founded on the principle that excellence should be felt in every detail.</p>
            </div>
          )}
        </div>

      </main>

      <footer style={{ textAlign: 'center', padding: '40px 0', opacity: 0.3 }}>
         <p style={{ fontSize: '0.5rem', letterSpacing: '3px', color: gold }}>LAGOS | EST. 2026</p>
      </footer>
    </div>
  );
}

export default App;
